29	    // Mark the trait as a relation trait
30	    traitCtx.relation = null!; // Will be set below after relation is created
31	
32	    // Handle autoDestroy option - 'orphan' is an alias for 'source'
33	    let autoDestroy: 'source' | 'target' | false = false;
34	    if (definition?.autoDestroy === 'orphan' || definition?.autoDestroy === 'source') {
